// src/app/dashboard/[id]/page.tsx
import { createClient } from "@/app/lib/supabase/server";
import Link from "next/link";
import { ArrowLeft, FileText } from "lucide-react";
import JobAssistant from "@/app/components/JobAssistant";
import ScoreChart from "@/app/components/ScoreChart";

interface PageProps {
  params: Promise<{ id: string }>;
}

export default async function ResumeDetailPage({ params }: PageProps) {
  const { id } = await params;
  const supabase = await createClient();

  // Log current auth user on the server
  try {
    const userRes = await supabase.auth.getUser();
    console.log("DEBUG supabase.auth.getUser():", JSON.stringify(userRes, null, 2));
  } catch (e) {
    console.log("DEBUG supabase.auth.getUser() failed:", e);
  }

  // Try the full select (with relationship). Catch and log detailed error.
  let resume: any = null;
  let queryError: any = null;

  try {
    const { data, error, status, statusText } = await supabase
      .from("resumes")
      .select(
        `
        *,
        analyses (
          id, resume_id, user_id, ats_score, summary_feedback, skills_found, missing_keywords, formatting_issues, created_at
        )
      `
      )
      .eq("id", id)
      .maybeSingle();

    resume = data;
    if (error) {
      queryError = { error, status, statusText };
      console.error("Supabase select error (with analyses):", JSON.stringify({ error, status, statusText }, null, 2));
    } else {
      console.log("DEBUG resume row (with analyses):", resume);
    }
  } catch (err) {
    console.error("Supabase query threw:", err);
    queryError = { thrown: String(err) };
  }

  // If selecting with relationship failed or returned nothing useful,
  // fall back to a minimal select to ensure we can at least fetch the resume row.
  if (!resume && !queryError?.error) {
    try {
      const { data, error, status, statusText } = await supabase
        .from("resumes")
        .select("*")
        .eq("id", id)
        .maybeSingle();
      resume = data;
      if (error) {
        queryError = { error, status, statusText };
        console.error("Supabase minimal select error:", JSON.stringify({ error, status, statusText }, null, 2));
      } else {
        console.log("DEBUG resume row (minimal):", resume);
      }
    } catch (err) {
      console.error("Supabase minimal query threw:", err);
      queryError = { thrown: String(err) };
    }
  }

  // If final resume still missing or queryError exists, show friendly debug UI
  if (!resume || queryError) {
    return (
      <div className="max-w-4xl mx-auto py-20 px-4 text-center">
        <h2 className="text-xl font-semibold mb-2">Could not load resume</h2>
        <p className="text-sm text-gray-600 mb-4">Possible causes: Row-Level Security (RLS) / policies, missing permissions, or the Supabase client not passing auth correctly.</p>

        <div className="text-left bg-white p-4 rounded border max-w-3xl mx-auto">
          <h4 className="font-medium mb-2">Debug info</h4>
          <pre className="text-xs p-2 bg-slate-50 rounded">{JSON.stringify({ queryError, resume }, null, 2)}</pre>

          <div className="mt-3 text-xs text-gray-500">
            <p><strong>Quick checks:</strong></p>
            <ol className="list-decimal list-inside">
              <li>Are RLS policies enabled on <code>resumes</code> or <code>analyses</code>?</li>
              <li>Does your policy allow SELECT for authenticated users? (see SQL below)</li>
              <li>Is the server client created correctly (with cookies) in <code>src/app/lib/supabase/server.ts</code>?</li>
            </ol>
          </div>

          <Link href="/dashboard" className="inline-block mt-4 text-indigo-600">Return to Dashboard</Link>
        </div>
      </div>
    );
  }

  // Parse analysisData (either original JSON column or related analyses array)
  let analysisData: any = null;
  if ((resume as any).original_analysis) {
    try {
      analysisData =
        typeof (resume as any).original_analysis === "string"
          ? JSON.parse((resume as any).original_analysis)
          : (resume as any).original_analysis;
    } catch {
      analysisData = (resume as any).original_analysis;
    }
  }

  if (!analysisData && Array.isArray((resume as any).analyses) && (resume as any).analyses.length > 0) {
    const arr = [...(resume as any).analyses];
    arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
    analysisData = arr[0];
  }

  const score = (analysisData && typeof analysisData.ats_score === "number" && analysisData.ats_score) || 0;

  return (
    <div className="max-w-5xl mx-auto py-10 px-4 sm:px-6">
      <Link href="/dashboard" className="inline-flex items-center text-sm text-gray-500 hover:text-indigo-600 mb-6">
        <ArrowLeft className="w-4 h-4 mr-2" />
        Back to Dashboard
      </Link>

      <div className="flex items-center gap-4 mb-8 pb-6 border-b border-gray-200">
        <div className="p-3 bg-indigo-50 rounded-lg">
          <FileText className="w-8 h-8 text-indigo-600" />
        </div>
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{(resume as any).file_name || "Untitled Resume"}</h1>
          <p className="text-sm text-gray-500">Uploaded on {new Date((resume as any).created_at).toLocaleDateString()}</p>
        </div>
      </div>

      <div className="grid md:grid-cols-3 gap-6 mb-8">
        <div className="md:col-span-2">
          {analysisData ? (
            <div className="bg-white p-4 rounded-lg border">
              <div className="mb-3 text-sm text-gray-600">Detected score: <strong>{score}</strong></div>
              <div style={{ width: 360, height: 220 }}>
                <ScoreChart score={score} />
              </div>
              <hr className="my-3" />
              <div>
                <h4 className="font-semibold text-sm mb-2">Latest analysis JSON</h4>
                <pre className="text-xs p-3 bg-slate-50 rounded overflow-x-auto" style={{ maxHeight: 300 }}>
                  {JSON.stringify(analysisData, null, 2)}
                </pre>
              </div>
            </div>
          ) : (
            <div className="p-6 bg-white border rounded-lg text-gray-500 h-64 flex items-center justify-center">
              No analysis data available for this resume.
            </div>
          )}
        </div>

        <div className="bg-white p-6 rounded-lg border shadow-sm h-fit">
          <h3 className="font-semibold text-gray-900 mb-2">Details</h3>
          <div className="text-sm text-gray-500 space-y-2">
            <p>Status: <span className="text-green-600 font-medium">Active</span></p>
            <p>Type: { (resume as any).file_type || "PDF" }</p>
          </div>
        </div>
      </div>

      <JobAssistant resumeId={id} />
    </div>
  );
}
